function applyOverviewFilters(){
  var filterEl = document.getElementById('ovFilter');
  var searchEl = document.getElementById('ovSearch');
  var v = filterEl ? filterEl.value : 'all';
  var term = ((searchEl && searchEl.value) || '').trim().toLowerCase();
  var crossSet = new Set(['tax4b.wrapper','tax4b.dbobjects','tax4b.nomos-db','tax4b.nomos-js','tax4b.nomos-odata','tax4b.koine-db']);

  document.querySelectorAll('#overviewTable tbody tr').forEach(function(tr){
    var up = tr.getAttribute('data-up') === '1';
    var name = (tr.children[0] && tr.children[0].textContent || '').trim();
    var lname = name.toLowerCase();
    var show = false;

    if (v==='all') show = true;
    else if (v==='up') show = up;
    else if (v==='down') show = !up;
    else if (v==='cross') show = crossSet.has(name);
    else if (v==='db') show = lname.endsWith('-db');
    else if (v==='js') show = lname.endsWith('-js');
    else if (v==='odata') show = lname.endsWith('-odata');
    else if (v==='ui') show = lname.endsWith('-ui');
    else if (v==='backend') show = lname.endsWith('-backend');

    if (show && term) {
      show = lname.indexOf(term) !== -1;
    }

    tr.style.display = show ? '' : 'none';
  });

  try{
    if (typeof window !== 'undefined' && typeof window.__ovUpdateBulkSelectionCount === 'function') {
      window.__ovUpdateBulkSelectionCount();
    } else {
      var totalVisible = 0;
      var selectedVisible = 0;
      document.querySelectorAll('#overviewTable tbody tr').forEach(function(tr){
        if(tr.style && tr.style.display==='none') return;
        totalVisible++;
        var chk = tr.querySelector('input.ovSel');
        if(chk && chk.checked) selectedVisible++;
      });
      var totalEl = document.getElementById('bulkSummaryTotal');
      var selectedEl = document.getElementById('bulkSummarySelected');
      if(totalEl) totalEl.textContent = String(totalVisible);
      if(selectedEl) selectedEl.textContent = String(selectedVisible);
      var all = document.getElementById('chkSelectAllVisible');
      if(all){
        all.checked = !!totalVisible && totalVisible === selectedVisible;
        all.indeterminate = selectedVisible > 0 && selectedVisible < totalVisible;
      }
    }

    if (typeof window !== 'undefined' && typeof window.__ovScheduleBulkSummaryRefresh === 'function') {
      window.__ovScheduleBulkSummaryRefresh();
    }
  }catch(_){}
}

