  async downloadAppLogs(req,res){
    try{
      const { envId, objectId, password, deployVersion } = req.body || {};
      if (!req.session?.user) {
        return res.status(401).json({ ok:false, error:'Unauthorized' });
      }
      if (!envId || !objectId || !password) {
        return res.status(400).json({ ok:false, error:'Parâmetros insuficientes para baixar o log.' });
      }

      const env = await this.envSvc.getById(Number(envId));
      if (!env) return res.status(404).json({ ok:false, error:'Ambiente não encontrado.' });
      if (!env.org_url) return res.status(400).json({ ok:false, error:'Ambiente sem URL da organização.' });
      if (!env.username) return res.status(400).json({ ok:false, error:'Ambiente sem usuário configurado.' });

      const rawType = (env && typeof env.env_type === 'string' ? env.env_type : '').trim().toUpperCase();
      const normType = (rawType === 'CLOUD FOUNDRY') ? 'CF' : ((rawType === 'XSA') ? 'XS' : rawType);
      let CLI_BIN = (normType === 'XS')
        ? ((process.env.XS_BIN && process.env.XS_BIN.trim()) || 'xs')
        : ((process.env.CF_BIN && process.env.CF_BIN.trim()) || 'cf');

      if (env && typeof env.org_url === 'string' && /\bapi\.cf\./i.test(env.org_url)) {
        CLI_BIN = ((process.env.CF_BIN && process.env.CF_BIN.trim()) || 'cf');
      }

      const _quoteIfNeeded = (v) => ensureCliArgQuoted(v);
      const loginArgs = ['login','-a',env.org_url,'--skip-ssl-validation','-u',env.username,'-p',String(password)];
      if (env.org)   loginArgs.push('-o', _quoteIfNeeded(env.org));
      if (env.space) loginArgs.push('-s', _quoteIfNeeded(env.space));

      const sLogin = await runCmd(CLI_BIN, loginArgs);
      if (sLogin.code !== 0) {
        return res.status(500).json({ ok:false, error: (sLogin.stderr || sLogin.stdout || 'Falha no login do ambiente').slice(0,2000) });
      }

      const originalAppName = String(objectId).trim();
      const appName = originalAppName.replace(/\./g, '-');
      const isCF = String(CLI_BIN).toLowerCase().includes('cf');
      const logArgs = isCF
        ? ['logs', appName, '--recent']
        : ['logs', appName, '--last', '1000'];

      const sLogs = await runCmd(CLI_BIN, logArgs);
      const out = [sLogs.stdout || '', sLogs.stderr || ''].filter(Boolean).join('\n').trim();
      let effectiveDeployVersion = (deployVersion !== undefined && deployVersion !== null) ? String(deployVersion).trim() : '';
      if (!effectiveDeployVersion) {
        try {
          effectiveDeployVersion = String(await this.appsSvc.latestVersionFor(originalAppName) || '').trim();
        } catch (_) {}
      }
      const headerLines = [
        'Componente original: ' + originalAppName + (effectiveDeployVersion ? (' | Versão deploy: ' + effectiveDeployVersion) : ''),
        'Ambiente: ' + String(env.name || env.id || ''),
        'Comando: ' + (isCF ? ('cf logs ' + appName + ' --recent') : ('xs logs ' + appName + ' --last 1000'))
      ];
      const content = [
        headerLines.join('\n'),
        '',
        out || 'Nenhum conteúdo de log retornado pelo comando.'
      ].join('\n');

      const safeName = originalAppName.replace(/[^a-zA-Z0-9._-]+/g, '_');
      res.setHeader('Content-Type', 'text/plain; charset=utf-8');
      res.setHeader('Content-Disposition', 'attachment; filename="logs-' + safeName + '.log"');
      return res.status(200).send(content);
    }catch(e){
      return res.status(500).json({ ok:false, error: (e && e.message) ? e.message : String(e) });
    }
  }

